mapper.select:
SELECT id, receiver_id, title, content, message_type, read_status, read_at, created_at, updated_at, deleted FROM sys_message WHERE deleted = 0
AND (title LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%') OR message_type LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}
